import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import {
  Dialog,
  Box,
  IconButton,
  Button,
  Typography,
  useTheme,
  alpha,
  Chip,
  Tooltip,
  CircularProgress
} from '@mui/material';
import {
  Close as CloseIcon,
  ArrowBackIos as ArrowBackIcon,
  ArrowForwardIos as ArrowForwardIcon,
  CalendarToday as CalendarIcon,
  SmartToy as AssistantIcon,
  Slideshow as SlideshowIcon,
  StickyNote2 as GamePlanIcon,
  EventNote as EconomicIcon
} from '@mui/icons-material';
import { format, parseISO } from 'date-fns';
import { Trade, Calendar } from '../types/dualWrite';
import { EconomicEvent } from '../types/economicCalendar';
import { Note, DayAbbreviation } from '../types/note';
import TradeDetailExpanded from './TradeDetailExpanded';
import { scrollbarStyles } from '../styles/scrollbarStyles';
import { TradeOperationsProps } from '../types/tradeOperations';
import { useAIChat } from '../hooks/useAIChat';
import { QuestionTemplate } from './aiChat/AIChatInterface';
import OrionPanel from './aiChat/OrionPanel';
import { useAuthState } from '../contexts/AuthStateContext';
import Shimmer from './Shimmer';
import EconomicEventDetailDialog from './economicCalendar/EconomicEventDetailDialog';
import EconomicEventsPanel from './economicCalendar/EconomicEventsPanel';
import NoteViewerPanel from './notes/NoteViewerPanel';
import { logger } from '../utils/logger';
import { Z_INDEX } from '../styles/zIndex';
import { getTradeRepository } from '../services/calendarService';
import {
  getReminderNotesForDay,
  getReminderNotesForDate,
} from '../services/notesService';
import { useTradeSyncContextOptional } from '../contexts/TradeSyncContext';
import { normalizeTradeDates } from '../utils/tradeUtils';
import { DEFAULT_FILTER_SETTINGS as DEFAULT_ECONOMIC_EVENT_FILTER_SETTINGS } from '../hooks/useEconomicCalendarFilters';

interface TradeGalleryDialogProps {
  open: boolean;
  onClose: () => void;
  trades: Trade[];
  initialTradeId?: string;
  setZoomedImage: (url: string, allImages?: string[], initialIndex?: number) => void;
  title?: string;
  calendarId?: string;
  // Calendar data for economic events filtering
  calendar?: Calendar;
  // AI-only mode: starts on Assistant tab
  aiOnlyMode?: boolean;
  isReadOnly?: boolean;
  // Fetch mode: if set, dialog will fetch trades for this year when trades array is empty
  fetchYear?: number;
  // External loading state (e.g. parent is fetching a trade to display)
  loading?: boolean;

  // Trade operations - required
  tradeOperations: TradeOperationsProps;
}

// Page size for paginated fetching
const GALLERY_PAGE_SIZE = 20;

const TradeGalleryDialog: React.FC<TradeGalleryDialogProps> = ({
  open,
  onClose,
  trades,
  initialTradeId,
  setZoomedImage,
  title = "Trade Gallery",
  calendarId,
  calendar,
  aiOnlyMode = false,
  isReadOnly = false,
  fetchYear,
  loading: externalLoading = false,
  tradeOperations
}) => {
  // Destructure from tradeOperations directly
  const {
    onUpdateTradeProperty,
    onOpenGalleryMode,
    onEditTrade,
    onDeleteTrade,
    onDeleteMultipleTrades,
    onUpdateCalendarProperty,
    isTradeUpdating
  } = tradeOperations;

  // Subscribe to trade sync context for real-time updates
  const tradeSync = useTradeSyncContextOptional();
  const lastProcessedTimestamp = useRef(0);

  const theme = useTheme();
  const { user } = useAuthState();
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  // Orion side-panel — auto-open in aiOnlyMode (where the user explicitly
  // launched the dialog into chat mode).
  const [orionOpen, setOrionOpen] = useState(aiOnlyMode);
  const [orionShowHistory, setOrionShowHistory] = useState(false);

  // Economic events side-panel (mutex with Orion + Note viewer).
  const [eventsOpen, setEventsOpen] = useState(false);

  // Game plan fetch state. The button lives in the gallery header (not
  // in TradeDetailExpanded any more), so the dialog owns the fetch and
  // routes the resolved note into the existing NoteViewerPanel flow.
  const [loadingGamePlan, setLoadingGamePlan] = useState(false);
  const [gamePlanCache, setGamePlanCache] = useState<Record<string, Note[]>>({});
  // Token for the in-flight game-plan fetch. Reset by trade nav or by
  // opening another panel so a slow fetch can't force the note viewer
  // open after the user has moved on.
  const gamePlanRequestRef = useRef<string | null>(null);

  // Fetch mode state - used when trades array is empty and fetchYear is set
  const [internalTrades, setInternalTrades] = useState<Trade[]>([]);
  const [isLoadingTrades, setIsLoadingTrades] = useState(false);
  const [hasMoreTrades, setHasMoreTrades] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  // Derive initial total count from calendar year_stats, then update from API response
  const initialTotalCount = fetchYear !== undefined
    ? calendar?.year_stats?.[fetchYear.toString()]?.total_trades ?? 0
    : 0;
  const [totalTradeCount, setTotalTradeCount] = useState(initialTotalCount);

  // Determine if we're in fetch mode (no trades provided but fetchYear is set)
  const isFetchMode = trades.length === 0 && fetchYear !== undefined && calendarId !== undefined;

  // Use either provided trades or internally fetched trades
  const effectiveTrades = isFetchMode ? internalTrades : trades;

  // Find initial index based on initialTradeId
  const initialIndex = useMemo(() => {
    if (!initialTradeId) return 0;
    const index = effectiveTrades.findIndex(trade => trade.id === initialTradeId);
    return index >= 0 ? index : 0;
  }, [effectiveTrades, initialTradeId]);

  const [currentIndex, setCurrentIndex] = useState(initialIndex);

  // Update current index when initialTradeId changes
  useEffect(() => {
    setCurrentIndex(initialIndex);
  }, [initialIndex]);

  // Ensure currentIndex is within bounds (might be stale from previous session)
  const safeCurrentIndex = useMemo(() => {
    if (effectiveTrades.length === 0) return 0;
    return Math.min(Math.max(0, currentIndex), effectiveTrades.length - 1);
  }, [currentIndex, effectiveTrades.length]);

  // Get current trade using safe index
  const currentTrade = useMemo(() => {
    if (effectiveTrades.length === 0) return null;
    return effectiveTrades[safeCurrentIndex] || null;
  }, [effectiveTrades, safeCurrentIndex]);

  // Fetch initial trades when in fetch mode and dialog opens
  useEffect(() => {
    const fetchInitialTrades = async () => {
      if (!isFetchMode || !open || !calendarId || fetchYear === undefined) return;

      // Don't re-fetch if we already have trades
      if (internalTrades.length > 0) return;

      setIsLoadingTrades(true);
      try {
        const result = await getTradeRepository().getTradesForYearPaginated(
          calendarId,
          fetchYear,
          1,
          GALLERY_PAGE_SIZE
        );

        setInternalTrades(result.trades);
        setHasMoreTrades(result.hasMore);
        setCurrentPage(1);
        setTotalTradeCount(result.totalCount);
        setCurrentIndex(0);

        logger.log(`📖 Gallery: Initial fetch - ${result.trades.length} trades, hasMore: ${result.hasMore}, total: ${result.totalCount}`);
      } catch (error) {
        logger.error('Error fetching initial trades:', error);
      } finally {
        setIsLoadingTrades(false);
      }
    };

    fetchInitialTrades();
  }, [isFetchMode, open, calendarId, fetchYear]);

  // Load more trades when approaching the end (within last 2 trades)
  const loadMoreTrades = useCallback(async () => {
    if (!isFetchMode || isLoadingTrades || !hasMoreTrades || !calendarId || fetchYear === undefined) {
      return;
    }

    setIsLoadingTrades(true);
    try {
      const nextPage = currentPage + 1;
      const result = await getTradeRepository().getTradesForYearPaginated(
        calendarId,
        fetchYear,
        nextPage,
        GALLERY_PAGE_SIZE
      );

      setInternalTrades(prev => [...prev, ...result.trades]);
      setHasMoreTrades(result.hasMore);
      setCurrentPage(nextPage);

      logger.log(`📖 Gallery: Loaded page ${nextPage} - ${result.trades.length} more trades, hasMore: ${result.hasMore}`);
    } catch (error) {
      logger.error('Error loading more trades:', error);
    } finally {
      setIsLoadingTrades(false);
    }
  }, [isFetchMode, isLoadingTrades, hasMoreTrades, calendarId, fetchYear, currentPage]);

  // Trigger load more when user is near the end
  useEffect(() => {
    if (!isFetchMode || !hasMoreTrades || isLoadingTrades) return;

    // Load more when within last 2 trades (use safeCurrentIndex for accurate calculation)
    const tradesRemaining = effectiveTrades.length - safeCurrentIndex - 1;
    if (tradesRemaining <= 1) {
      loadMoreTrades();
    }
  }, [safeCurrentIndex, effectiveTrades.length, isFetchMode, hasMoreTrades, isLoadingTrades, loadMoreTrades]);

  // Reset internal state when dialog closes, sync totalTradeCount when opening
  useEffect(() => {
    if (!open) {
      setInternalTrades([]);
      setCurrentPage(1);
      setHasMoreTrades(false);
      setTotalTradeCount(initialTotalCount);
    } else {
      // Sync total count from calendar stats when dialog opens
      setTotalTradeCount(initialTotalCount);
    }
  }, [open, initialTotalCount]);

  // Handle trade sync events from other components (e.g., useCalendarTrades)
  useEffect(() => {
    if (!tradeSync?.lastSyncEvent || !open) return;

    const { type, trade, timestamp } = tradeSync.lastSyncEvent;

    // Avoid processing the same event twice
    if (timestamp <= lastProcessedTimestamp.current) return;
    lastProcessedTimestamp.current = timestamp;

    // Only process events for trades in our calendar
    if (calendarId && trade.calendar_id !== calendarId) return;

    const normalizedTrade = normalizeTradeDates(trade);

    // Update internalTrades if in fetch mode
    if (isFetchMode) {
      setInternalTrades(prevTrades => {
        switch (type) {
          case 'update': {
            const tradeIndex = prevTrades.findIndex(t => t.id === trade.id);
            if (tradeIndex === -1) return prevTrades;

            const updatedTrades = [...prevTrades];
            updatedTrades[tradeIndex] = normalizedTrade;
            logger.log(`📖 Gallery: Synced trade update for ${trade.id}`);
            return updatedTrades;
          }
          case 'delete': {
            const filteredTrades = prevTrades.filter(t => t.id !== trade.id);
            if (filteredTrades.length === prevTrades.length) return prevTrades;
            logger.log(`📖 Gallery: Synced trade delete for ${trade.id}`);
            return filteredTrades;
          }
          default:
            return prevTrades;
        }
      });
    }
  }, [tradeSync?.lastSyncEvent, open, calendarId, isFetchMode]);

  // Economic event detail dialog state
  const [selectedEvent, setSelectedEvent] = useState<EconomicEvent | null>(null);
  const [eventDetailDialogOpen, setEventDetailDialogOpen] = useState(false);

  // Note viewer panel state — replaces nested dialogs to avoid
  // z-index conflicts with this gallery dialog.
  const [viewerNote, setViewerNote] = useState<Note | null>(null);
  const [viewerNoteId, setViewerNoteId] = useState<string | null>(null);
  const [viewerLoading, setViewerLoading] = useState(false);
  const [viewerOpen, setViewerOpen] = useState(false);
  const [viewerEmptyTitle, setViewerEmptyTitle] = useState<string>(
    'Nothing to show'
  );
  const [viewerEmptyMessage, setViewerEmptyMessage] = useState<string>(
    'No content available.'
  );

  // Open with a fully-loaded note (used by AI chat when embeddedNotes
  // are present and by game plan once notes are fetched).
  // Passing `null` means "loading completed with no result" — keep
  // the panel open and show an empty state so the user gets explicit
  // feedback instead of a flash-and-close.
  const handleOpenNote = useCallback((note: Note | null) => {
    setViewerNote(note);
    setViewerNoteId(null);
    setViewerLoading(false);
    setViewerOpen(true);
    setOrionOpen(false); // Right slot is mutex — close any other panel
    setEventsOpen(false);
  }, []);

  // Open immediately with shimmer; the panel fetches by id internally.
  // Used for AI chat references whose embedded payload was lost (e.g.
  // history-loaded conversations).
  const handleOpenNoteById = useCallback((noteId: string) => {
    setViewerNote(null);
    setViewerNoteId(noteId);
    setViewerLoading(false);
    setViewerOpen(true);
    setOrionOpen(false);
    setEventsOpen(false);
  }, []);

  // Open immediately with shimmer; caller will populate via
  // handleOpenNote when its async work completes (e.g. game plan
  // day-based query, where we don't know the id up front). The
  // optional emptyMessage is shown if the caller resolves to no note.
  const handleOpenNoteLoading = useCallback(
    (opts?: { emptyTitle?: string; emptyMessage?: string }) => {
      setViewerNote(null);
      setViewerNoteId(null);
      setViewerLoading(true);
      setViewerOpen(true);
      setOrionOpen(false);
      setEventsOpen(false);
      if (opts?.emptyTitle) setViewerEmptyTitle(opts.emptyTitle);
      if (opts?.emptyMessage) setViewerEmptyMessage(opts.emptyMessage);
    },
    []
  );

  // Opening Orion closes any other panel. State for every side is
  // dialog-level (aiChat hook + viewerNote/viewerNoteId + EventsPanel
  // fetched data), so reopening any panel restores its previous content
  // — no loss of conversation, viewed note, or filter state.
  const handleToggleOrion = useCallback(() => {
    setOrionOpen((prev) => {
      const next = !prev;
      if (next) {
        setViewerOpen(false);
        setEventsOpen(false);
        gamePlanRequestRef.current = null; // cancel any in-flight game-plan fetch
      }
      return next;
    });
  }, []);

  const handleToggleEvents = useCallback(() => {
    setEventsOpen((prev) => {
      const next = !prev;
      if (next) {
        setOrionOpen(false);
        setViewerOpen(false);
        gamePlanRequestRef.current = null;
      }
      return next;
    });
  }, []);

  const handleCloseNoteViewer = useCallback(() => {
    setViewerOpen(false);
    setViewerLoading(false);
    // Clear note/id after slide-out animation finishes
    window.setTimeout(() => {
      setViewerNote(null);
      setViewerNoteId(null);
    }, 300);
  }, []);

  // Game plan: opens NoteViewerPanel with the day's reminder note(s).
  // Cached per trade.id so toggling the panel after the first open is
  // instant — no re-fetch flicker. The token-ref race guard above
  // makes a stale resolution a no-op while still populating the cache.
  const handleOpenGamePlan = useCallback(async () => {
    if (!currentTrade?.trade_date) return;
    const tradeId = currentTrade.id;
    const effectiveCalendarId = calendarId || currentTrade.calendar_id;
    if (!effectiveCalendarId) return;

    const cached = gamePlanCache[tradeId];
    if (cached) {
      if (cached.length > 0) handleOpenNote(cached[0]);
      else handleOpenNote(null);
      return;
    }

    // Show shimmer immediately; populate when the fetch resolves.
    handleOpenNoteLoading({
      emptyTitle: 'No game plan',
      emptyMessage: 'No game plan available for this day.',
    });

    const requestToken = tradeId;
    gamePlanRequestRef.current = requestToken;
    setLoadingGamePlan(true);
    try {
      const date =
        typeof currentTrade.trade_date === 'string'
          ? parseISO(currentTrade.trade_date)
          : currentTrade.trade_date;
      const dayAbbr = format(date, 'EEE') as DayAbbreviation;

      const [weeklyNotes, dateNotes] = await Promise.all([
        getReminderNotesForDay(effectiveCalendarId, dayAbbr),
        getReminderNotesForDate(effectiveCalendarId, date),
      ]);

      // Exclude every-day reminders — those aren't day-specific game
      // plans. One-time date reminders always qualify.
      const daySpecificNotes = weeklyNotes.filter(
        (note) => !note.reminder_days || note.reminder_days.length < 7,
      );

      const merged = [...daySpecificNotes, ...dateNotes];
      const unique = merged.filter(
        (note, idx, arr) => arr.findIndex((n) => n.id === note.id) === idx,
      );

      // Always cache so a later open is instant, even if this resolution
      // is stale w.r.t. the open panel.
      setGamePlanCache((prev) => ({ ...prev, [tradeId]: unique }));
      if (gamePlanRequestRef.current !== requestToken) return;
      if (unique.length > 0) handleOpenNote(unique[0]);
      else handleOpenNote(null);
    } catch (err) {
      logger.error('Error fetching game plan notes:', err);
      if (gamePlanRequestRef.current === requestToken) handleOpenNote(null);
    } finally {
      if (gamePlanRequestRef.current === requestToken) {
        gamePlanRequestRef.current = null;
        setLoadingGamePlan(false);
      }
    }
  }, [currentTrade, calendarId, gamePlanCache, handleOpenNote, handleOpenNoteLoading]);

  // Immersive mode state
  const [immersiveMode, setImmersiveMode] = useState(false);
  const [immersiveImageIndex, setImmersiveImageIndex] = useState(0);

  // Track previous trade ID to detect trade changes
  const previousTradeIdRef = useRef<string | null>(null);

  // When navigating between trades, close transient panels whose
  // contents were tied to the previous trade. Orion stays open (the
  // conversation reset below keeps it scoped) but its history pager
  // collapses back to the chat view. Events panel closes because its
  // session-window fetch is trade-scoped. Any in-flight game-plan
  // fetch is invalidated so its resolution doesn't pop the viewer
  // back open on the new trade.
  useEffect(() => {
    setOrionShowHistory(false);
    setViewerOpen(false);
    setViewerNote(null);
    setViewerNoteId(null);
    setViewerLoading(false);
    setEventsOpen(false);
    gamePlanRequestRef.current = null;
  }, [safeCurrentIndex]);

  // Clear panel state whenever the dialog closes so it doesn't
  // re-appear stale on the next open with a different trade.
  useEffect(() => {
    if (!open) {
      setViewerOpen(false);
      setViewerNote(null);
      setViewerNoteId(null);
      setViewerLoading(false);
      setEventsOpen(false);
    }
  }, [open]);

  // Initialize AI chat with trade-scoped context
  const aiChat = useAIChat({
    userId: user?.uid,
    calendar: calendar,
    trade: currentTrade || undefined,
    autoSaveConversation: true, // Enable saving for trade-specific conversations
  });

  // Reset conversation when trade changes (each trade has its own history)
  useEffect(() => {
    const currentTradeId = currentTrade?.id || null;

    // If trade changed, reset the conversation
    if (previousTradeIdRef.current !== null && previousTradeIdRef.current !== currentTradeId) {
      aiChat.setMessages([]);
    }

    previousTradeIdRef.current = currentTradeId;
  }, [currentTrade?.id, aiChat.setMessages]);

  // Load trade-specific conversations when Orion panel opens.
  useEffect(() => {
    if (orionOpen && currentTrade?.id && user?.uid) {
      aiChat.loadConversations();
    }
  }, [orionOpen, currentTrade?.id, user?.uid, aiChat.loadConversations]);

  // Single trade context for AI to focus on
  const tradeContext = useMemo(() => {
    return currentTrade ? [currentTrade] : [];
  }, [currentTrade]);

  // Generate trade-specific question templates
  const tradeQuestionTemplates: QuestionTemplate[] = useMemo(() => {
    if (!currentTrade) return [];

    const tradeName = currentTrade.name || 'this trade';
    const tradeType = currentTrade.trade_type;
    const isWin = tradeType === 'win';
    const isLoss = tradeType === 'loss';

    return [
      {
        category: "Trade Analysis",
        questions: [
          `Why did ${tradeName} ${isWin ? 'succeed' : isLoss ? 'fail' : 'break even'}?`,
          `What patterns do you see in this trade's setup?`,
          `Analyze the entry and exit timing for this trade`
        ]
      },
      {
        category: "Compare & Learn",
        questions: [
          `Show me similar trades from my history`,
          `How does this trade compare to my winning trades?`,
          `What could I have done differently in this trade?`
        ]
      },
      {
        category: "Risk & Management",
        questions: [
          `Was my position size appropriate for this trade?`,
          `Analyze the risk-reward ratio of this trade`,
          `Did I follow my trading rules on this trade?`
        ]
      }
    ];
  }, [currentTrade]);

  const handleToggleOrionHistory = useCallback(() => {
    setOrionShowHistory((prev) => !prev);
  }, []);

  // Navigation functions
  // Check if we're at the last trade and loading more (use safeCurrentIndex for accurate checks)
  const isAtEnd = safeCurrentIndex >= effectiveTrades.length - 1;
  const isAtStart = safeCurrentIndex <= 0;
  const isLoadingNext = isLoadingTrades && isAtEnd && hasMoreTrades;
  const isLoadingPrev = isLoadingTrades && isAtStart && isFetchMode;

  const navigateNext = useCallback(() => {
    if (effectiveTrades.length <= 1) return;
    // In fetch mode, don't wrap around - just go to next if available
    if (isFetchMode) {
      if (safeCurrentIndex < effectiveTrades.length - 1) {
        setCurrentIndex(safeCurrentIndex + 1);
      }
    } else {
      // Normal mode - wrap around
      setCurrentIndex((safeCurrentIndex + 1) % effectiveTrades.length);
    }
  }, [effectiveTrades.length, isFetchMode, safeCurrentIndex]);

  const navigatePrevious = useCallback(() => {
    if (effectiveTrades.length <= 1) return;
    // In fetch mode, don't wrap around
    if (isFetchMode) {
      if (safeCurrentIndex > 0) {
        setCurrentIndex(safeCurrentIndex - 1);
      }
    } else {
      // Normal mode - wrap around
      setCurrentIndex((safeCurrentIndex - 1 + effectiveTrades.length) % effectiveTrades.length);
    }
  }, [effectiveTrades.length, isFetchMode, safeCurrentIndex]);

  // Scroll functions
  const scrollUp = useCallback(() => {
    if (scrollContainerRef.current) {
      scrollContainerRef.current.scrollBy({
        top: -200,
        behavior: 'smooth'
      });
    }
  }, []);

  const scrollDown = useCallback(() => {
    if (scrollContainerRef.current) {
      scrollContainerRef.current.scrollBy({
        top: 200,
        behavior: 'smooth'
      });
    }
  }, []);

  // Get current trade's images for immersive mode
  const currentImages = useMemo(() => {
    if (!currentTrade?.images) return [];
    return currentTrade.images.filter(img => !img.pending);
  }, [currentTrade?.images]);

  // Reset immersive image index when trade changes
  useEffect(() => {
    setImmersiveImageIndex(0);
  }, [safeCurrentIndex]);

  // Handle keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!open) return;

      if (immersiveMode) {
        if (e.key === 'Escape') {
          e.preventDefault();
          e.stopPropagation();
          setImmersiveMode(false);
          return;
        }
        if (e.key === 'ArrowLeft') {
          e.preventDefault();
          if (immersiveImageIndex > 0) {
            setImmersiveImageIndex(prev => prev - 1);
          } else {
            navigatePrevious();
          }
        } else if (e.key === 'ArrowRight') {
          e.preventDefault();
          if (immersiveImageIndex < currentImages.length - 1) {
            setImmersiveImageIndex(prev => prev + 1);
          } else {
            navigateNext();
          }
        }
        return;
      }

      if (e.key === 'ArrowLeft') {
        e.preventDefault();
        navigatePrevious();
      } else if (e.key === 'ArrowRight') {
        e.preventDefault();
        navigateNext();
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        scrollUp();
      } else if (e.key === 'ArrowDown') {
        e.preventDefault();
        scrollDown();
      } else if (e.key === 'Escape') {
        e.preventDefault();
        onClose();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, [
    open, immersiveMode, immersiveImageIndex, currentImages.length,
    navigatePrevious, navigateNext, scrollUp, scrollDown, onClose
  ]);

  // Determine if we're in initial loading state (fetch mode, loading, no trades yet)
  const isInitialLoading =
    externalLoading || (isFetchMode && isLoadingTrades && effectiveTrades.length === 0);

  // Only return null if not in fetch mode and no trade
  if (!currentTrade && !isInitialLoading) {
    return null;
  }

  return (
    <Dialog
      open={open}
      onClose={onClose}
      maxWidth="md"
      fullWidth
      sx={{
        zIndex: Z_INDEX.DIALOG_POPUP
      }}
      PaperProps={{
        sx: {
          // Lock to a stable height range so the dialog doesn't
          // collapse when the active tab has minimal content
          // (e.g. an empty AI chat).
          height: '90vh',
          minHeight: { xs: '85vh', sm: 600 },
          maxHeight: '90vh',
          display: 'flex',
          flexDirection: 'column',
          backgroundColor: theme.palette.background.default,
          overflow: 'hidden',
          position: 'relative'
        }
      }}
    >
      {/* Header */}
      <Box sx={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        p: 2,
        borderBottom: `1px solid ${theme.palette.divider}`,
        backgroundColor: theme.palette.background.paper
      }}>

        <Box sx={{ display: 'flex', flex: 1 }}>
          {/* Navigation and Title */}
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, minWidth: 0 }}>
            {/* Previous Button */}
            <Tooltip
              title={isInitialLoading ? "Loading..." : isAtStart && isFetchMode ? "At first trade" : "Previous trade (←)"}
              slotProps={{ popper: { sx: { zIndex: Z_INDEX.TOOLTIP } } }}
            >
              <span>
                <IconButton
                  onClick={navigatePrevious}
                  disabled={isInitialLoading || effectiveTrades.length <= 1 || (isAtStart && isFetchMode)}
                  sx={{
                    color: isInitialLoading || effectiveTrades.length <= 1 || (isAtStart && isFetchMode) ? 'text.disabled' : 'text.primary',
                    '&:hover': {
                      backgroundColor: alpha(theme.palette.primary.main, 0.1)
                    }
                  }}
                >
                  <ArrowBackIcon />
                </IconButton>
              </span>
            </Tooltip>

            {/* Title and Counter */}
            <Box sx={{ display: 'flex', flexDirection: 'column', gap: 0.5, minWidth: 0 }}>
              <Typography variant="h6" sx={{
                fontWeight: 600,
                wordBreak: 'break-word',
                overflowWrap: 'break-word'
              }}>
                {title}
              </Typography>
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, flexWrap: 'wrap' }}>
                {isInitialLoading ? (
                  <Shimmer height={24} width={80} borderRadius={12} variant="wave" intensity="medium" />
                ) : (
                  <Chip
                    size="small"
                    label={isFetchMode
                      ? `${safeCurrentIndex + 1} of ${totalTradeCount}`
                      : `${safeCurrentIndex + 1} of ${effectiveTrades.length}`
                    }
                    sx={{
                      backgroundColor: alpha(theme.palette.primary.main, 0.1),
                      color: 'primary.main',
                      fontWeight: 600
                    }}
                  />
                )}
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                  <CalendarIcon sx={{ fontSize: 16, color: 'text.secondary' }} />
                  {isInitialLoading ? (
                    <Shimmer height={14} width={100} borderRadius={4} variant="wave" intensity="low" />
                  ) : (
                    <Typography variant="caption" color="text.secondary" sx={{
                      wordBreak: 'break-word',
                      overflowWrap: 'break-word'
                    }}>
                      {format(new Date(currentTrade!.trade_date), 'MMM d, yyyy')}
                    </Typography>
                  )}
                </Box>
              </Box>
            </Box>

            {/* Next Button */}
            <Tooltip
              title={isLoadingNext ? "Loading more trades..." : isAtEnd && !hasMoreTrades && isFetchMode ? "At last trade" : "Next trade (→)"}
              slotProps={{ popper: { sx: { zIndex: Z_INDEX.TOOLTIP } } }}
            >
              <span>
                <IconButton
                  onClick={navigateNext}
                  disabled={effectiveTrades.length <= 1 || isLoadingNext || (isAtEnd && !hasMoreTrades && isFetchMode)}
                  sx={{
                    color: effectiveTrades.length <= 1 || (isAtEnd && !hasMoreTrades && isFetchMode) ? 'text.disabled' : 'text.primary',
                    '&:hover': {
                      backgroundColor: alpha(theme.palette.primary.main, 0.1)
                    }
                  }}
                >
                  {isLoadingNext ? (
                    <CircularProgress size={20} color="primary" />
                  ) : (
                    <ArrowForwardIcon />
                  )}
                </IconButton>
              </span>
            </Tooltip>
          </Box>
        </Box>

        {/* Tabs, Immersive, and History Controls */}
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, ml: 2 }}>
          {/* Immersive Mode Button */}
          {!isInitialLoading && currentTrade?.images &&
            currentTrade.images.length > 0 && (
            <Tooltip
              title="Immersive Mode — browse trade images"
              slotProps={{
                popper: { sx: { zIndex: Z_INDEX.TOOLTIP } }
              }}
            >
              <IconButton
                size="small"
                onClick={() => {
                  setImmersiveImageIndex(0);
                  setImmersiveMode(true);
                }}
                sx={{
                  color: 'text.secondary',
                  '&:hover': {
                    backgroundColor: alpha(
                      theme.palette.primary.main, 0.1
                    ),
                    color: 'primary.main'
                  }
                }}
              >
                <SlideshowIcon sx={{ fontSize: 20 }} />
              </IconButton>
            </Tooltip>
          )}

          {/* Game Plan — opens the day's reminder note in NoteViewerPanel.
              Hidden when the trade has no calendar context (nothing to
              fetch against). */}
          {(calendarId || currentTrade?.calendar_id) && (
            <Tooltip
              title="Open game plan for this day"
              slotProps={{ popper: { sx: { zIndex: Z_INDEX.TOOLTIP } } }}
            >
              <span>
                <IconButton
                  size="small"
                  onClick={handleOpenGamePlan}
                  disabled={loadingGamePlan}
                  sx={{
                    color: 'text.secondary',
                    '&:hover': {
                      backgroundColor: alpha(theme.palette.primary.main, 0.1),
                      color: 'primary.main',
                    },
                    '&:disabled': { color: 'text.disabled' },
                  }}
                >
                  {loadingGamePlan ? (
                    <CircularProgress size={18} color="inherit" />
                  ) : (
                    <GamePlanIcon sx={{ fontSize: 20 }} />
                  )}
                </IconButton>
              </span>
            </Tooltip>
          )}

          {/* Economic Events toggle — opens the session-window events
              panel. Active state when the panel is currently open. */}
          {currentTrade?.session && (
            <Tooltip
              title={eventsOpen ? 'Close events' : 'Economic events for this session'}
              slotProps={{ popper: { sx: { zIndex: Z_INDEX.TOOLTIP } } }}
            >
              <IconButton
                size="small"
                onClick={handleToggleEvents}
                sx={{
                  color: eventsOpen ? 'primary.main' : 'text.secondary',
                  bgcolor: eventsOpen
                    ? alpha(theme.palette.primary.main, 0.12)
                    : 'transparent',
                  '&:hover': {
                    backgroundColor: alpha(theme.palette.primary.main, 0.1),
                    color: 'primary.main',
                  },
                }}
              >
                <EconomicIcon sx={{ fontSize: 20 }} />
              </IconButton>
            </Tooltip>
          )}

          {/* Ask Orion toggle — opens the side panel. Active state when
              the panel is currently open. */}
          <Tooltip
            title={orionOpen ? 'Close Orion' : 'Ask Orion about this trade'}
            slotProps={{ popper: { sx: { zIndex: Z_INDEX.TOOLTIP } } }}
          >
            <IconButton
              size="small"
              onClick={handleToggleOrion}
              sx={{
                color: orionOpen ? 'primary.main' : 'text.secondary',
                bgcolor: orionOpen
                  ? alpha(theme.palette.primary.main, 0.12)
                  : 'transparent',
                '&:hover': {
                  backgroundColor: alpha(theme.palette.primary.main, 0.1),
                  color: 'primary.main',
                },
              }}
            >
              <AssistantIcon sx={{ fontSize: 20 }} />
            </IconButton>
          </Tooltip>
        </Box>

        {/* Close Button */}
        <IconButton
          onClick={onClose}
          sx={{
            color: 'text.secondary',
            '&:hover': {
              backgroundColor: alpha(theme.palette.error.main, 0.1),
              color: 'error.main'
            }
          }}
        >
          <CloseIcon />
        </IconButton>
      </Box>

      {/* Body: flex row with main content (left) + slide-in panels (right).
          Orion and the note viewer share the right slot via mutex (one
          open at a time), so both panels render as direct flex siblings
          and only one ever has non-zero width. */}
      <Box sx={{
        display: 'flex',
        flexDirection: 'row',
        flex: 1,
        minHeight: 0,
        overflow: 'hidden'
      }}>
      {/* Main content column — shrinks when note panel opens */}
      <Box sx={{
        flex: 1,
        minWidth: 0,
        display: 'flex',
        flexDirection: 'column',
        overflow: 'hidden'
      }}>

      {/* Trade detail — always rendered. Orion lives in the right
          slide-in slot, not behind a tab. */}
      <Box
        ref={scrollContainerRef}
        sx={{
          flex: 1,
          minHeight: 0,
          overflow: 'auto',
          ...scrollbarStyles(theme)
        }}
      >
          {isInitialLoading ? (
            // Shimmer loading state matching TradeDetailExpanded structure
            <Box sx={{ p: 3, display: 'flex', flexDirection: 'column', gap: 3 }}>
              {/* Trade name row: Icon + Name + Action buttons */}
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5 }}>
                  <Shimmer height={28} width={28} borderRadius={4} variant="wave" intensity="medium" />
                  <Shimmer height={28} width={120} borderRadius={4} variant="wave" intensity="medium" />
                </Box>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                  <Shimmer height={32} width={32} borderRadius="50%" variant="wave" intensity="low" />
                  <Shimmer height={32} width={32} borderRadius="50%" variant="wave" intensity="low" />
                  <Shimmer height={32} width={32} borderRadius="50%" variant="wave" intensity="low" />
                </Box>
              </Box>

              {/* Properties Section Header */}
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                <Shimmer height={16} width={16} borderRadius={4} variant="wave" intensity="low" />
                <Shimmer height={16} width={80} borderRadius={4} variant="wave" intensity="low" />
              </Box>

              {/* Properties 2x2 Grid */}
              <Box sx={{
                display: 'grid',
                gridTemplateColumns: { xs: '1fr', sm: '1fr 1fr' },
                gap: 2
              }}>
                {/* PnL Card */}
                <Box sx={{
                  p: 2,
                  borderRadius: 2,
                  bgcolor: theme.palette.background.paper,
                  border: `1px solid ${alpha(theme.palette.divider, 0.1)}`
                }}>
                  <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5, mb: 1 }}>
                    <Shimmer height={14} width={14} borderRadius={4} variant="wave" intensity="low" />
                    <Shimmer height={14} width={30} borderRadius={4} variant="wave" intensity="low" />
                  </Box>
                  <Shimmer height={28} width={80} borderRadius={4} variant="wave" intensity="medium" />
                </Box>

                {/* Date Card */}
                <Box sx={{
                  p: 2,
                  borderRadius: 2,
                  bgcolor: theme.palette.background.paper,
                  border: `1px solid ${alpha(theme.palette.divider, 0.1)}`
                }}>
                  <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5, mb: 1 }}>
                    <Shimmer height={14} width={14} borderRadius={4} variant="wave" intensity="low" />
                    <Shimmer height={14} width={35} borderRadius={4} variant="wave" intensity="low" />
                  </Box>
                  <Shimmer height={20} width={130} borderRadius={4} variant="wave" intensity="medium" />
                </Box>

                {/* Risk to Reward Card */}
                <Box sx={{
                  p: 2,
                  borderRadius: 2,
                  bgcolor: theme.palette.background.paper,
                  border: `1px solid ${alpha(theme.palette.divider, 0.1)}`
                }}>
                  <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5, mb: 1 }}>
                    <Shimmer height={14} width={14} borderRadius={4} variant="wave" intensity="low" />
                    <Shimmer height={14} width={90} borderRadius={4} variant="wave" intensity="low" />
                  </Box>
                  <Shimmer height={24} width={40} borderRadius={4} variant="wave" intensity="medium" sx={{ mb: 0.5 }} />
                  <Shimmer height={14} width={120} borderRadius={4} variant="wave" intensity="low" />
                </Box>

                {/* Session Card */}
                <Box sx={{
                  p: 2,
                  borderRadius: 2,
                  bgcolor: theme.palette.background.paper,
                  border: `1px solid ${alpha(theme.palette.divider, 0.1)}`
                }}>
                  <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5, mb: 1 }}>
                    <Shimmer height={14} width={14} borderRadius={4} variant="wave" intensity="low" />
                    <Shimmer height={14} width={55} borderRadius={4} variant="wave" intensity="low" />
                  </Box>
                  <Shimmer height={20} width={60} borderRadius={4} variant="wave" intensity="medium" />
                </Box>
              </Box>

              {/* Images Section */}
              <Box>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2 }}>
                  <Shimmer height={16} width={16} borderRadius={4} variant="wave" intensity="low" />
                  <Shimmer height={16} width={55} borderRadius={4} variant="wave" intensity="low" />
                </Box>
                <Box sx={{ display: 'flex', gap: 2 }}>
                  <Shimmer height={100} width="100%" borderRadius={2} variant="wave" intensity="medium" sx={{ flex: 1 }} />
                  <Shimmer height={100} width="100%" borderRadius={2} variant="wave" intensity="medium" sx={{ flex: 1 }} />
                  <Shimmer height={100} width="100%" borderRadius={2} variant="wave" intensity="medium" sx={{ flex: 1 }} />
                </Box>
              </Box>

              {/* Tags Section */}
              <Box>
                <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
                  <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                    <Shimmer height={16} width={16} borderRadius={4} variant="wave" intensity="low" />
                    <Shimmer height={16} width={40} borderRadius={4} variant="wave" intensity="low" />
                  </Box>
                  <Shimmer height={20} width={20} borderRadius={4} variant="wave" intensity="low" />
                </Box>
                <Box sx={{ display: 'flex', gap: 1, flexWrap: 'wrap' }}>
                  {[140, 180, 100, 160, 80, 100, 80, 120].map((width, i) => (
                    <Shimmer key={i} height={28} width={width} borderRadius={14} variant="wave" intensity="medium" />
                  ))}
                </Box>
              </Box>
            </Box>
          ) : currentTrade ? (
            <TradeDetailExpanded
              tradeData={currentTrade}
              isExpanded={true}
              animate={false}
              trades={trades}
              tradeOperations={{
                ...tradeOperations,
                onOpenGalleryMode: undefined
              }}
            />
          ) : null}
        </Box>
      </Box>{/* /Main content column */}

      {/* Orion side-panel — direct flex sibling so its % widths
          resolve against the real flex-row width. */}
      <OrionPanel
        open={orionOpen}
        onClose={() => setOrionOpen(false)}
        aiChat={aiChat}
        showHistory={orionShowHistory}
        onToggleHistory={handleToggleOrionHistory}
        userId={user?.uid}
        calendar={calendar}
        trades={tradeContext}
        questionTemplates={tradeQuestionTemplates}
        isReadOnly={isReadOnly}
        onTradeClick={(tradeId, contextTrades) => {
          const tradeIndex = effectiveTrades.findIndex((t) => t.id === tradeId);
          if (tradeIndex >= 0 && effectiveTrades.length <= 5) {
            setCurrentIndex(tradeIndex);
          } else if (onOpenGalleryMode) {
            onOpenGalleryMode(contextTrades, tradeId, 'AI Chat - Trade Gallery');
          } else {
            logger.log('Trade clicked but not found in gallery:', tradeId);
          }
        }}
        onEventClick={(event) => {
          setSelectedEvent(event);
          setEventDetailDialogOpen(true);
        }}
        onNoteClick={(noteId, note) => {
          if (note) {
            handleOpenNote(note);
          } else {
            handleOpenNoteById(noteId);
          }
        }}
      />

      {/* EconomicEventsPanel — direct flex sibling. Owns its own
          fetch + filter + realtime sub. Mutex enforced at the
          toggle handlers, so only one panel ever has non-zero width. */}
      <EconomicEventsPanel
        open={eventsOpen}
        onClose={() => setEventsOpen(false)}
        trade={currentTrade}
        filterSettings={
          calendar?.economic_calendar_filters ||
          DEFAULT_ECONOMIC_EVENT_FILTER_SETTINGS
        }
      />

      {/* NoteViewerPanel — direct flex sibling. The right slot is
          mutex with Orion + Events (handleOpenNote* + handleToggle*
          enforce one-at-a-time) so no overlay is needed. All panels
          keep their content via dialog-level state, so toggling
          between them is non-destructive. */}
      <NoteViewerPanel
        open={viewerOpen}
        onClose={handleCloseNoteViewer}
        note={viewerNote}
        noteId={viewerNoteId}
        loading={viewerLoading}
        emptyTitle={viewerEmptyTitle}
        emptyMessage={viewerEmptyMessage}
      />
      </Box>{/* /Flex row */}

      {/* Economic Event Detail Dialog */}
      {selectedEvent && calendar && (
        <EconomicEventDetailDialog
          open={eventDetailDialogOpen}
          onClose={() => {
            setEventDetailDialogOpen(false);
            setSelectedEvent(null);
          }}
          event={selectedEvent}
          calendarId={calendar.id}
          tradeOperations={tradeOperations}
          isReadOnly={isReadOnly}
        />
      )}

      {/* Immersive Mode Overlay */}
      {immersiveMode && currentTrade && currentImages.length > 0 && (
        <Box
          sx={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            zIndex: Z_INDEX.DIALOG_POPUP + 10,
            backgroundColor: '#000',
            display: 'flex',
            flexDirection: 'column',
            userSelect: 'none'
          }}
        >
          {/* Top bar: date + counter + exit */}
          <Box sx={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            px: 3,
            py: 1.5,
            background:
              'linear-gradient(to bottom, rgba(0,0,0,0.7), transparent)',
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            zIndex: 2
          }}>
            <Box sx={{
              display: 'flex', alignItems: 'center', gap: 1.5
            }}>
              <CalendarIcon sx={{ fontSize: 18, color: '#fff' }} />
              <Typography sx={{
                color: '#fff', fontWeight: 600, fontSize: '0.95rem'
              }}>
                {format(
                  new Date(currentTrade.trade_date), 'MMM d, yyyy'
                )}
              </Typography>
              {currentTrade.name && (
                <Typography sx={{
                  color: alpha('#fff', 0.6),
                  fontSize: '0.85rem',
                  ml: 0.5
                }}>
                  — {currentTrade.name}
                </Typography>
              )}
            </Box>

            <Box sx={{
              display: 'flex', alignItems: 'center', gap: 1.5
            }}>
              <Chip
                size="small"
                label={`${immersiveImageIndex + 1} / ${currentImages.length}`}
                sx={{
                  backgroundColor: alpha('#fff', 0.15),
                  color: '#fff',
                  fontWeight: 600,
                  fontSize: '0.8rem'
                }}
              />
              <Chip
                size="small"
                label={isFetchMode
                  ? `Trade ${safeCurrentIndex + 1} of ${totalTradeCount}`
                  : `Trade ${safeCurrentIndex + 1} of ${effectiveTrades.length}`
                }
                sx={{
                  backgroundColor: alpha('#fff', 0.15),
                  color: '#fff',
                  fontWeight: 600,
                  fontSize: '0.8rem'
                }}
              />
              <Button
                variant="contained"
                size="small"
                startIcon={<CloseIcon sx={{ fontSize: 16 }} />}
                onClick={() => setImmersiveMode(false)}
                sx={{
                  backgroundColor: alpha('#fff', 0.15),
                  color: '#fff',
                  textTransform: 'none',
                  fontWeight: 600,
                  fontSize: '0.8rem',
                  '&:hover': {
                    backgroundColor: alpha('#fff', 0.25)
                  }
                }}
              >
                Exit
              </Button>
            </Box>
          </Box>

          {/* Image area */}
          <Box sx={{
            flex: 1,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            position: 'relative',
            overflow: 'hidden'
          }}>
            {/* Previous arrow */}
            <IconButton
              onClick={() => {
                if (immersiveImageIndex > 0) {
                  setImmersiveImageIndex(prev => prev - 1);
                } else {
                  navigatePrevious();
                }
              }}
              disabled={immersiveImageIndex === 0 &&
                (isAtStart && isFetchMode)}
              sx={{
                position: 'absolute',
                left: 16,
                zIndex: 3,
                color: '#fff',
                backgroundColor: alpha('#fff', 0.1),
                '&:hover': {
                  backgroundColor: alpha('#fff', 0.2)
                },
                '&.Mui-disabled': {
                  color: alpha('#fff', 0.2)
                }
              }}
            >
              <ArrowBackIcon />
            </IconButton>

            {/* Current image */}
            <Box
              component="img"
              src={currentImages[immersiveImageIndex]?.url}
              alt={currentImages[immersiveImageIndex]?.caption
                || `Trade image ${immersiveImageIndex + 1}`}
              sx={{
                maxWidth: '90%',
                maxHeight: '85vh',
                objectFit: 'contain',
                borderRadius: 1,
                transition: 'opacity 0.2s ease'
              }}
            />

            {/* Next arrow */}
            <IconButton
              onClick={() => {
                if (immersiveImageIndex < currentImages.length - 1) {
                  setImmersiveImageIndex(prev => prev + 1);
                } else {
                  navigateNext();
                }
              }}
              disabled={
                immersiveImageIndex === currentImages.length - 1 &&
                isAtEnd && !hasMoreTrades && isFetchMode
              }
              sx={{
                position: 'absolute',
                right: 16,
                zIndex: 3,
                color: '#fff',
                backgroundColor: alpha('#fff', 0.1),
                '&:hover': {
                  backgroundColor: alpha('#fff', 0.2)
                },
                '&.Mui-disabled': {
                  color: alpha('#fff', 0.2)
                }
              }}
            >
              <ArrowForwardIcon />
            </IconButton>
          </Box>

          {/* Thumbnail strip */}
          {currentImages.length > 1 && (
            <Box sx={{
              display: 'flex',
              justifyContent: 'center',
              gap: 1,
              pb: 2,
              px: 3,
              background:
                'linear-gradient(to top, rgba(0,0,0,0.7), transparent)',
              position: 'absolute',
              bottom: 0,
              left: 0,
              right: 0,
              pt: 3
            }}>
              {currentImages.map((img, idx) => (
                <Box
                  key={img.id}
                  onClick={() => setImmersiveImageIndex(idx)}
                  component="img"
                  src={img.url}
                  alt={img.caption || `Thumbnail ${idx + 1}`}
                  sx={{
                    width: 56,
                    height: 40,
                    objectFit: 'cover',
                    borderRadius: 0.5,
                    cursor: 'pointer',
                    border: idx === immersiveImageIndex
                      ? '2px solid #fff'
                      : '2px solid transparent',
                    opacity: idx === immersiveImageIndex ? 1 : 0.5,
                    transition: 'all 0.2s ease',
                    '&:hover': { opacity: 0.8 }
                  }}
                />
              ))}
            </Box>
          )}
        </Box>
      )}

    </Dialog>
  );
};

export default TradeGalleryDialog;
