import React, { useEffect, useMemo, useRef, useState, forwardRef, useImperativeHandle } from 'react';
import { Editor, EditorState, ContentState, CompositeDecorator, Modifier, SelectionState } from 'draft-js';
import { Box, Chip, Popper, Paper, List, ListItem, ListItemButton, Typography, useTheme, alpha } from '@mui/material';
import { Tag as TagIcon, Notes as NotesIcon, Bolt as BoltIcon } from '@mui/icons-material';
import { getTagChipStyles, formatTagForDisplay, isGroupedTag, getTagGroup } from '../../utils/tagColors';
import { scrollbarStyles } from '../../styles/scrollbarStyles';
import { Z_INDEX } from '../../styles/zIndex';
import { useDialogTokens } from '../../styles/dialogTokens';
import type { MessageSegment } from '../../utils/chatMentions';
import { detectMentionTrigger, extractSegments } from '../../utils/chatMentions';
import { SLASH_COMMAND_TAG } from '../../types/note';

export interface AIChatMentionInputHandle {
  focus: () => void;
  moveCursorToEnd: () => void;
  getSegments: () => MessageSegment[];
  /**
   * Replace the editor's content from a `MessageSegment[]` produced by a
   * previous `getSegments()` call. Note-mention segments become `NOTE_MENTION`
   * entities (chips); text segments become plain text. Used by the edit flow
   * to restore chip rendering for previously-sent messages.
   */
  setSegments: (segments: MessageSegment[]) => void;
  /** Imperatively dismiss the slash/mention popup if it's open. */
  closeMention: () => void;
}

/**
 * A locally-handled command shown in the slash popup. Selecting a system
 * command does NOT insert a chip or send anything to Orion — it consumes the
 * `/term` text and fires `onSystemCommand(id)` so the parent can invoke an
 * app-level action (open a note, clear chat, etc.).
 */
export interface SystemCommand {
  id: string;
  title: string;
  subtitle?: string;
}

export interface AIChatMentionInputProps {
  value: string;
  onChange: (value: string) => void;
  onKeyDown?: (e: React.KeyboardEvent) => void;
  placeholder?: string;
  disabled?: boolean;
  allTags: string[];
  allNotes: { id: string; title: string; tags: string[] }[];
  systemCommands?: SystemCommand[];
  onSystemCommand?: (id: string) => void;
  maxRows?: number;
  sx?: any;
}

// Hoisted entity components — stable identity across mounts so Draft.js
// doesn't treat them as new component types on every decorator creation.
const TagMentionEntity = ({ contentState, entityKey }: any) => {
  const theme = useTheme();
  const { tag } = contentState.getEntity(entityKey).getData() as { tag: string };

  // Simple: render a Chip instead of the underlying text. We intentionally
  // do NOT render children here so the raw text is not shown.
  return (
    <Chip
      size="small"
      label={formatTagForDisplay(tag, true)}
      contentEditable={false}
      onMouseDown={(e) => e.preventDefault()}
      sx={{
        ...getTagChipStyles(tag, theme),
        height: 22,
        fontSize: '0.75rem',
        userSelect: 'none',
        verticalAlign: 'middle',
        display: 'inline-flex'
      }}
    />
  );
};
(TagMentionEntity as any).displayName = 'TagMentionEntity';

const NoteMentionEntity = ({ contentState, entityKey }: any) => {
  const theme = useTheme();
  const { noteTitle } = contentState.getEntity(entityKey).getData() as { noteTitle: string };

  return (
    <Chip
      size="small"
      label={noteTitle}
      contentEditable={false}
      onMouseDown={(e) => e.preventDefault()}
      sx={{
        height: 22,
        fontSize: '0.75rem',
        userSelect: 'none',
        verticalAlign: 'middle',
        display: 'inline-flex',
        backgroundColor: alpha(theme.palette.info.main, 0.1),
        color: theme.palette.info.main,
        border: `1px solid ${alpha(theme.palette.info.main, 0.3)}`,
        '&:hover': {
          backgroundColor: alpha(theme.palette.info.main, 0.2)
        }
      }}
    />
  );
};
(NoteMentionEntity as any).displayName = 'NoteMentionEntity';

const createMentionDecorator = () =>
  new CompositeDecorator([
    {
      // Render tag mentions as chips
      strategy: (block, callback, contentState) => {
        block.findEntityRanges(
          ch => {
            const k = ch.getEntity();
            return !!k && contentState.getEntity(k).getType() === 'TAG_MENTION';
          },
          (start, end) => callback(start, end)
        );
      },
      component: TagMentionEntity
    },
    {
      // Render note mentions as chips
      strategy: (block, callback, contentState) => {
        block.findEntityRanges(
          ch => {
            const k = ch.getEntity();
            return !!k && contentState.getEntity(k).getType() === 'NOTE_MENTION';
          },
          (start, end) => callback(start, end)
        );
      },
      component: NoteMentionEntity
    }
  ]);

type MentionItem =
  | { type: 'note'; id: string; title: string }
  | { type: 'tag'; tag: string }
  | { type: 'system'; id: string; title: string; subtitle?: string };

const AIChatMentionInput = forwardRef<AIChatMentionInputHandle, AIChatMentionInputProps>(({
  value, onChange, onKeyDown, placeholder, disabled, allTags, allNotes,
  systemCommands, onSystemCommand, maxRows = 4, sx
}, ref) => {
  const theme = useTheme();
  const {
    violet, violetSoft, violetSofter, violetBorder,
    surfaceInset, hairline,
    paperSx, monoSectionLabelSx,
  } = useDialogTokens();
  const editorRef = useRef<Editor>(null as any);
  const [editorState, setEditorState] = useState(() => EditorState.createWithContent(ContentState.createFromText(value || ''), createMentionDecorator()));
  const editorStateRef = useRef(editorState);
  const [editorKey, setEditorKey] = useState(0);
  const [mention, setMention] = useState<{
    open: boolean;
    kind: 'slash' | 'at';
    term: string;
    start: number;
    blockKey: string;
  } | null>(null);
  const [anchorEl, setAnchorEl] = useState<HTMLElement | null>(null);
  // -1 = no selection. First ArrowDown/ArrowUp moves it onto an item.
  // Enter does nothing while idx === -1 — user must explicitly navigate first.
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const containerRef = useRef<HTMLDivElement>(null);
  const popperRef = useRef<HTMLDivElement>(null);
  const listRef = useRef<HTMLUListElement>(null);
  const moveCursorToEndOnNextUpdate = useRef(false);

  useImperativeHandle(ref, () => ({
    focus: () => editorRef.current && (editorRef.current as any).focus?.(),
    moveCursorToEnd: () => {
      // Set flag to move cursor to end on next value update
      moveCursorToEndOnNextUpdate.current = true;

      // Also try to move it immediately if possible
      const currentContent = editorStateRef.current.getCurrentContent();
      const lastBlock = currentContent.getLastBlock();
      const lastBlockKey = lastBlock.getKey();
      const length = lastBlock.getLength();

      const selection = SelectionState.createEmpty(lastBlockKey).merge({
        anchorOffset: length,
        focusOffset: length
      }) as SelectionState;

      const newState = EditorState.forceSelection(editorStateRef.current, selection);
      setEditorState(newState);

      // Focus after setting selection
      setTimeout(() => {
        (editorRef.current as any)?.focus?.();
      }, 0);
    },
    getSegments: () => extractSegments(editorStateRef.current),
    closeMention: () => setMention(null),
    setSegments: (segments: MessageSegment[]) => {
      // Build a fresh ContentState block-by-block, applying NOTE_MENTION
      // entities for note-mention segments. Result is a single block
      // containing text+chips (newlines in text segments stay as soft breaks
      // within the same block — fine for chat input which is rarely
      // multi-line for mentions).
      let content = ContentState.createFromText('');
      const blockKey = content.getFirstBlock().getKey();
      let cursor = 0;

      const insertAt = (text: string) => {
        const sel = SelectionState.createEmpty(blockKey).merge({
          anchorOffset: cursor,
          focusOffset: cursor,
        }) as SelectionState;
        content = Modifier.insertText(content, sel, text);
        cursor += text.length;
      };

      for (const seg of segments) {
        if (seg.type === 'text') {
          insertAt(seg.value);
        } else {
          const start = cursor;
          insertAt(seg.noteTitle);
          content = content.createEntity('NOTE_MENTION', 'IMMUTABLE', {
            noteTitle: seg.noteTitle,
            noteId: seg.noteId,
          });
          const entityKey = content.getLastCreatedEntityKey();
          const range = SelectionState.createEmpty(blockKey).merge({
            anchorOffset: start,
            focusOffset: cursor,
          }) as SelectionState;
          content = Modifier.applyEntity(content, range, entityKey);
        }
      }

      // Force-mount a fresh editor (matches the pattern used after
      // insertNoteFromMention — IMMUTABLE entity edges occasionally leave
      // stale DOM if we just push state into the existing editor).
      let newState = EditorState.createWithContent(content, createMentionDecorator());
      const tail = SelectionState.createEmpty(blockKey).merge({
        anchorOffset: cursor,
        focusOffset: cursor,
      }) as SelectionState;
      newState = EditorState.forceSelection(newState, tail);

      setEditorKey(k => k + 1);
      setEditorState(newState);
      editorStateRef.current = newState;

      // Notify parent so its `value` prop matches (avoids the sync effect
      // overwriting our chips on the next render).
      onChange(content.getPlainText());
    },
  }));

  useEffect(() => {
    // keep external value in sync if it changes from outside
    const currentText = editorState.getCurrentContent().getPlainText();
    if (value !== currentText) {
      const newContent = ContentState.createFromText(value || '');
      let newState = EditorState.createWithContent(newContent, createMentionDecorator());

      // If we should move cursor to end, do it now
      if (moveCursorToEndOnNextUpdate.current) {
        const lastBlock = newContent.getLastBlock();
        const lastBlockKey = lastBlock.getKey();
        const length = lastBlock.getLength();

        const selection = SelectionState.createEmpty(lastBlockKey).merge({
          anchorOffset: length,
          focusOffset: length
        }) as SelectionState;

        newState = EditorState.forceSelection(newState, selection);
        moveCursorToEndOnNextUpdate.current = false;

        // Focus the editor
        setTimeout(() => {
          (editorRef.current as any)?.focus?.();
        }, 0);
      }

      setEditorState(newState);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [value]);

  useEffect(() => {
    editorStateRef.current = editorState;
  }, [editorState]);

  useEffect(() => {
    if (editorKey > 0) {
      const raf = requestAnimationFrame(() => {
        try { (editorRef.current as any)?.focus?.(); } catch (_) {}
      });
      return () => cancelAnimationFrame(raf);
    }
  }, [editorKey]);

  const tags = useMemo(() => allTags.sort(), [allTags]);

  const filteredNotes = useMemo(() => {
    if (!mention) return [];
    const term = mention.term?.toLowerCase() ?? '';
    const kindPool =
      mention.kind === 'slash'
        ? allNotes.filter(n => (n.tags ?? []).includes(SLASH_COMMAND_TAG))
        : allNotes.filter(n => !(n.tags ?? []).includes(SLASH_COMMAND_TAG));
    return (term
      ? kindPool.filter(n => (n.title || '').toLowerCase().includes(term))
      : kindPool
    ).slice(0, 20);
  }, [allNotes, mention]);

  const filteredTags = useMemo(() => {
    if (!mention || mention.kind !== 'at') return [];
    const term = mention.term?.toLowerCase() ?? '';
    return (term ? tags.filter(t => t.toLowerCase().includes(term)) : tags).slice(0, 30);
  }, [tags, mention]);

  const filteredSystemCommands = useMemo(() => {
    if (!mention || mention.kind !== 'slash' || !systemCommands?.length) return [];
    const term = mention.term?.toLowerCase() ?? '';
    return term
      ? systemCommands.filter(c => c.title.toLowerCase().includes(term))
      : systemCommands;
  }, [systemCommands, mention]);

  const flatItems = useMemo<MentionItem[]>(() => [
    ...filteredSystemCommands.map(c => ({
      type: 'system' as const, id: c.id, title: c.title, subtitle: c.subtitle,
    })),
    ...filteredNotes.map(n => ({ type: 'note' as const, id: n.id, title: n.title })),
    ...filteredTags.map(t => ({ type: 'tag' as const, tag: t }))
  ], [filteredSystemCommands, filteredNotes, filteredTags]);

  useEffect(() => {
    if (!mention?.open) return;
    const list = listRef.current;
    if (!list) return;
    const selectableButtons = list.querySelectorAll<HTMLElement>('[data-mention-item="true"]');
    const target = selectableButtons[selectedIndex];
    if (target) target.scrollIntoView({ block: 'nearest' });
  }, [selectedIndex, mention?.open, flatItems.length]);

  // Dismiss the mention popup on any pointerdown outside the editor and the
  // popup itself — covers clicks on the history button, calendar picker,
  // pager swap, etc. Popper renders into a portal, so the editor's container
  // doesn't include it; we check both regions explicitly.
  useEffect(() => {
    if (!mention?.open) return;
    const handlePointerDown = (e: MouseEvent | TouchEvent) => {
      const target = e.target as Node | null;
      if (!target) return;
      if (containerRef.current?.contains(target)) return;
      if (popperRef.current?.contains(target)) return;
      setMention(null);
    };
    document.addEventListener('mousedown', handlePointerDown);
    document.addEventListener('touchstart', handlePointerDown);
    return () => {
      document.removeEventListener('mousedown', handlePointerDown);
      document.removeEventListener('touchstart', handlePointerDown);
    };
  }, [mention?.open]);

  function updateMentionState(state: EditorState) {
    const sel = state.getSelection();
    if (!sel.isCollapsed()) return setMention(null);
    const content = state.getCurrentContent();
    const blockKey = sel.getStartKey();
    const block = content.getBlockForKey(blockKey);
    const offset = sel.getStartOffset();
    const fullText = block.getText();

    const trigger = detectMentionTrigger(fullText, offset);
    if (!trigger) return setMention(null);

    setMention({
      open: true,
      kind: trigger.kind,
      term: trigger.term,
      start: trigger.start,
      blockKey,
    });
    setAnchorEl(containerRef.current);
    setSelectedIndex(-1);
  }

  function handleChange(state: EditorState) {
    setEditorState(state);
    onChange(state.getCurrentContent().getPlainText());
    updateMentionState(state);
  }

  function handleKeyDownLocal(e: React.KeyboardEvent) {
    if (mention?.open) {
      if (e.key === 'ArrowDown') {
        e.preventDefault();
        setSelectedIndex((i) => (i < 0 ? 0 : Math.min(i + 1, flatItems.length - 1)));
        return;
      }
      if (e.key === 'ArrowUp') {
        e.preventDefault();
        setSelectedIndex((i) => (i < 0 ? flatItems.length - 1 : Math.max(i - 1, 0)));
        return;
      }
      if (e.key === 'Enter') {
        // No-op when nothing is selected — Enter falls through to send the message
        // (or just inserts a newline) so users aren't forced to commit a slash.
        if (selectedIndex < 0) return;
        e.preventDefault();
        const item = flatItems[selectedIndex];
        if (item) {
          if (item.type === 'tag') insertTag(item.tag);
          else if (item.type === 'system') invokeSystemCommand(item.id);
          else insertNoteFromMention(item);
        }
        return;
      }
      if (e.key === 'Escape') { e.preventDefault(); setMention(null); return; }
    }

    // Prevent @ from being inserted - we'll handle it in handleChange via updateMentionState
    if (e.key === '@' && !e.ctrlKey && !e.metaKey && !e.altKey) {
      // Don't prevent default - let Draft.js insert the @ so updateMentionState can detect it
      // The @ will be replaced when a tag is selected
    }

    const sel = editorState.getSelection();
    if (sel.isCollapsed()) {
      const content = editorState.getCurrentContent();
      const block = content.getBlockForKey(sel.getStartKey());
      const offset = sel.getStartOffset();
      if (e.key === 'Backspace' && offset > 0) {
        const text = block.getText();
        if (text[offset - 1] === ' ' && offset > 1) {
          const ekBeforeSpace = block.getEntityAt(offset - 2);
          if (ekBeforeSpace) {
            const entityType = content.getEntity(ekBeforeSpace).getType();
            if (entityType === 'TAG_MENTION' || entityType === 'NOTE_MENTION') {
              e.preventDefault();
              handleRemoveEntity(ekBeforeSpace, true);
              return;
            }
          }
        }

        const ek = block.getEntityAt(offset - 1);
        if (ek) {
          const entityType = content.getEntity(ek).getType();
          if (entityType === 'TAG_MENTION' || entityType === 'NOTE_MENTION') {
            e.preventDefault();
            handleRemoveEntity(ek);
            return;
          }
        }
      }
    }
    onKeyDown?.(e);
  }

  // Consume the typed `/term` (no chip, no trailing space) and fire the
  // app-level handler. Used by system slash commands like "Clear Chat".
  function invokeSystemCommand(id: string) {
    const state = editorStateRef.current || editorState;
    const selection = state.getSelection();
    const atIndex = mention?.start ?? -1;
    if (!selection.isCollapsed() || atIndex === -1) {
      setMention(null);
      onSystemCommand?.(id);
      return;
    }

    const blockKey = selection.getStartKey();
    const offset = selection.getStartOffset();
    const removeSel = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex,
      focusOffset: offset,
    }) as SelectionState;
    const newContent = Modifier.removeRange(
      state.getCurrentContent(), removeSel, 'backward'
    );
    const cursor = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex,
      focusOffset: atIndex,
    }) as SelectionState;
    let newState = EditorState.createWithContent(newContent, createMentionDecorator());
    newState = EditorState.forceSelection(newState, cursor);

    setEditorKey(k => k + 1);
    setMention(null);
    handleChange(newState);
    onSystemCommand?.(id);
  }

  function insertNoteFromMention(note: { id: string; title: string }) {
    const state = editorStateRef.current || editorState;
    const selection = state.getSelection();
    if (!selection.isCollapsed()) { setMention(null); return; }

    const content = state.getCurrentContent();
    const blockKey = selection.getStartKey();
    const offset = selection.getStartOffset();

    const atIndex = mention?.start ?? -1;
    if (atIndex === -1) { setMention(null); return; }

    const noteTitle = note.title || 'Untitled';

    // Replace @term with the note title
    const replaceSel = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex,
      focusOffset: offset
    }) as SelectionState;
    let newContent = Modifier.replaceText(content, replaceSel, noteTitle);

    // Create NOTE_MENTION entity and apply it
    newContent = newContent.createEntity('NOTE_MENTION', 'IMMUTABLE', { noteTitle, noteId: note.id });
    const entityKey = newContent.getLastCreatedEntityKey();
    const entityRange = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex,
      focusOffset: atIndex + noteTitle.length
    }) as SelectionState;
    newContent = Modifier.applyEntity(newContent, entityRange, entityKey);

    // Insert trailing space
    const afterMention = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex + noteTitle.length,
      focusOffset: atIndex + noteTitle.length
    }) as SelectionState;
    newContent = Modifier.insertText(newContent, afterMention, ' ');

    // Create new state with forceSelection — use createWithContent to force full re-render
    // (EditorState.push can leave stale DOM when IMMUTABLE entities are adjacent)
    const cursorPosition = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex + noteTitle.length + 1,
      focusOffset: atIndex + noteTitle.length + 1
    }) as SelectionState;
    let newState = EditorState.createWithContent(newContent, createMentionDecorator());
    newState = EditorState.forceSelection(newState, cursorPosition);

    setEditorKey(k => k + 1);
    setMention(null);
    handleChange(newState);
  }

  function insertTag(tag: string) {
    // Always operate on the latest editor state
    const state = editorStateRef.current || editorState;
    const selection = state.getSelection();

    // We only handle collapsed selection (caret position)
    if (!selection.isCollapsed()) {
      setMention(null);
      return;
    }

    const content = state.getCurrentContent();
    const blockKey = selection.getStartKey();
    const offset = selection.getStartOffset();

    const atIndex = mention?.start ?? -1;
    if (atIndex === -1) { setMention(null); return; }

    const mentionText = tag; // raw tag, without '@'

    // Selection from '@' up to current caret position
    const replaceSel = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex,
      focusOffset: offset
    }) as SelectionState;

    // Step 1: replace the @mention text with the tag text
    let newContent = Modifier.replaceText(content, replaceSel, mentionText);

    // Step 2: create an entity for this tag and apply it over the inserted text
    newContent = newContent.createEntity('TAG_MENTION', 'IMMUTABLE', { tag });
    const entityKey = newContent.getLastCreatedEntityKey();

    const entityRange = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex,
      focusOffset: atIndex + mentionText.length
    }) as SelectionState;
    newContent = Modifier.applyEntity(newContent, entityRange, entityKey);

    // Step 3: insert a trailing space after the chip
    const afterMention = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex + mentionText.length,
      focusOffset: atIndex + mentionText.length
    }) as SelectionState;
    newContent = Modifier.insertText(newContent, afterMention, ' ');

    // Use createWithContent to force full re-render (EditorState.push leaves stale DOM
    // when IMMUTABLE entities are adjacent to the inserted text)
    const cursorPosition = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex + mentionText.length + 1,
      focusOffset: atIndex + mentionText.length + 1
    }) as SelectionState;
    let newState = EditorState.createWithContent(newContent, createMentionDecorator());
    newState = EditorState.forceSelection(newState, cursorPosition);

    setEditorKey(k => k + 1);
    setMention(null);
    handleChange(newState);
  }

  function handleRemoveEntity(entityKey: string, includeFollowingSpace = false) {
    const state = editorStateRef.current || editorState;
    const content = state.getCurrentContent();
    const blocks = content.getBlocksAsArray();
    for (const b of blocks) {
      let s = -1, e = -1;
      b.findEntityRanges(ch => ch.getEntity() === entityKey, (start, end) => { s = start; e = end; });
      if (s >= 0) {
        let focusOffset = e;
        if (includeFollowingSpace) {
          const txt = b.getText();
          if (txt[e] === ' ') focusOffset = e + 1;
        }
        const sel = SelectionState.createEmpty(b.getKey()).merge({ anchorOffset: s, focusOffset }) as SelectionState;
        const c2 = Modifier.removeRange(content, sel, 'backward');
        const st = EditorState.push(state, c2, 'remove-range');
        setEditorKey(k => k + 1);
        handleChange(st);
        return;
      }
    }
  }

  return (
    <Box ref={containerRef} sx={{ position: 'relative', width: '100%' }}>
      <Box
        onClick={() => editorRef.current && (editorRef.current as any).focus?.()}
        onKeyDown={handleKeyDownLocal}
        sx={{
          display: 'flex', flexWrap: 'wrap', alignItems: 'center', gap: 0.5,
          px: 1, py: 0.5, border: 'none', backgroundColor: 'transparent', cursor: 'text',
          width: '100%', maxWidth: '100%', minWidth: 0,
          '& .DraftEditor-root': { width: '100%' },
          '& .public-DraftEditor-content': {
            whiteSpace: 'pre-wrap',
            wordBreak: 'break-word',
            overflowWrap: 'anywhere',
            maxHeight: `${maxRows * 1.6}em`,
            overflowY: 'auto',
            ...scrollbarStyles(theme)
          },
          '& .public-DraftEditorPlaceholder-root': { whiteSpace: 'pre-wrap' },
          ...sx
        }}
      >
        <Editor
          key={editorKey}
          ref={editorRef as any}
          editorState={editorState}
          onChange={handleChange}
          readOnly={!!disabled}
          placeholder={placeholder}
          handleReturn={() => mention?.open ? 'handled' : 'not-handled'}
        />
      </Box>

      <Popper
        open={!!mention?.open}
        anchorEl={anchorEl}
        placement="top-start"
        sx={{ zIndex: Z_INDEX.RICH_TEXT_MENU }}
      >
        <Paper
          ref={popperRef}
          elevation={0}
          sx={{
            ...paperSx,
            maxHeight: 280,
            minWidth: 280,
            maxWidth: 420,
            mb: 0.75,
          }}
        >
          {/* Header band: mono section label + count pill */}
          <Box
            sx={{
              px: 1.5,
              py: 1,
              borderBottom: `1px solid ${hairline}`,
              backgroundColor: surfaceInset,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
              gap: 1,
            }}
          >
            <Typography
              sx={{
                ...monoSectionLabelSx,
                display: 'inline-flex',
                alignItems: 'center',
                gap: 0.625,
              }}
            >
              {mention?.kind === 'slash' ? (
                <BoltIcon sx={{ fontSize: 12 }} />
              ) : (
                <TagIcon sx={{ fontSize: 12 }} />
              )}
              {mention?.kind === 'slash' ? 'Slash commands' : 'Tags & notes'}
            </Typography>
            <Box
              sx={{
                px: 0.875,
                py: 0.125,
                borderRadius: 999,
                backgroundColor: violetSofter,
                border: `1px solid ${violetBorder}`,
                fontFamily: "'JetBrains Mono', ui-monospace, monospace",
                fontSize: '0.65rem',
                fontWeight: 600,
                color: violet,
                lineHeight: 1.4,
              }}
            >
              {flatItems.length}
            </Box>
          </Box>

          <List
            ref={listRef}
            sx={{ maxHeight: 220, overflow: 'auto', p: 0.5, ...scrollbarStyles(theme) }}
          >
            {flatItems.length === 0 ? (
              <ListItem>
                <Box sx={{ p: 2, textAlign: 'center', width: '100%' }}>
                  <Typography sx={{ fontSize: '0.82rem', color: theme.palette.text.secondary }}>
                    {allTags.length === 0 && allNotes.length === 0 && !systemCommands?.length
                      ? 'No tags or notes available.'
                      : mention?.kind === 'slash'
                        ? `No slash commands match "${mention?.term || ''}".`
                        : `No matches for "${mention?.term || ''}"`}
                  </Typography>
                </Box>
              </ListItem>
            ) : (
              <>
                {filteredSystemCommands.length > 0 && (
                  <>
                    <ListItem
                      sx={{
                        py: 0.5,
                        px: 1.25,
                        mt: 0.25,
                      }}
                    >
                      <Typography
                        sx={{
                          ...monoSectionLabelSx,
                          fontSize: '0.58rem',
                          display: 'inline-flex',
                          alignItems: 'center',
                          gap: 0.5,
                        }}
                      >
                        <BoltIcon sx={{ fontSize: 10 }} /> System
                      </Typography>
                    </ListItem>
                    {filteredSystemCommands.map((cmd, idx) => (
                      <ListItem key={cmd.id} disablePadding sx={{ px: 0.5 }}>
                        <ListItemButton
                          data-mention-item="true"
                          selected={idx === selectedIndex}
                          onMouseDown={(e) => { e.preventDefault(); invokeSystemCommand(cmd.id); }}
                          onClick={(e) => { e.preventDefault(); invokeSystemCommand(cmd.id); }}
                          sx={{
                            py: 0.875,
                            px: 1.25,
                            display: 'block',
                            borderRadius: 1.25,
                            '&.Mui-selected': {
                              backgroundColor: violetSoft,
                              color: violet,
                              '&:hover': { backgroundColor: violetSoft },
                            },
                            '&:hover': { backgroundColor: violetSofter },
                          }}
                        >
                          <Typography sx={{ fontSize: '0.85rem', fontWeight: 600 }} noWrap>
                            {cmd.title}
                          </Typography>
                          {cmd.subtitle && (
                            <Typography
                              sx={{ fontSize: '0.74rem', color: theme.palette.text.secondary }}
                              noWrap
                            >
                              {cmd.subtitle}
                            </Typography>
                          )}
                        </ListItemButton>
                      </ListItem>
                    ))}
                  </>
                )}
                {filteredNotes.length > 0 && (
                  <>
                    <ListItem
                      sx={{
                        py: 0.5,
                        px: 1.25,
                        mt: filteredSystemCommands.length > 0 ? 0.5 : 0.25,
                      }}
                    >
                      <Typography
                        sx={{
                          ...monoSectionLabelSx,
                          fontSize: '0.58rem',
                          display: 'inline-flex',
                          alignItems: 'center',
                          gap: 0.5,
                        }}
                      >
                        {mention?.kind === 'slash' ? (
                          <>
                            <BoltIcon sx={{ fontSize: 10 }} /> Slash commands
                          </>
                        ) : (
                          <>
                            <NotesIcon sx={{ fontSize: 10 }} /> Notes
                          </>
                        )}
                      </Typography>
                    </ListItem>
                    {filteredNotes.map((note, idx) => {
                      const flatIdx = filteredSystemCommands.length + idx;
                      const isSlashNote = mention?.kind === 'slash';
                      return (
                        <ListItem key={note.id} disablePadding sx={{ px: 0.5 }}>
                          <ListItemButton
                            data-mention-item="true"
                            selected={flatIdx === selectedIndex}
                            onMouseDown={(e) => { e.preventDefault(); insertNoteFromMention(note); }}
                            onClick={(e) => { e.preventDefault(); insertNoteFromMention(note); }}
                            sx={{
                              py: 0.875,
                              px: 1.25,
                              borderRadius: 1.25,
                              display: isSlashNote ? 'flex' : 'block',
                              alignItems: isSlashNote ? 'center' : undefined,
                              gap: isSlashNote ? 1 : undefined,
                              '&.Mui-selected': {
                                backgroundColor: violetSoft,
                                color: violet,
                                '& .slash-icon': {
                                  backgroundColor: violet,
                                  color: '#fff',
                                  borderColor: violet,
                                },
                                '&:hover': { backgroundColor: violetSoft },
                              },
                              '&:hover': { backgroundColor: violetSofter },
                            }}
                          >
                            {isSlashNote && (
                              <Box
                                className="slash-icon"
                                sx={{
                                  flexShrink: 0,
                                  width: 22,
                                  height: 22,
                                  borderRadius: 1,
                                  display: 'flex',
                                  alignItems: 'center',
                                  justifyContent: 'center',
                                  fontFamily: "'JetBrains Mono', ui-monospace, monospace",
                                  fontSize: '0.78rem',
                                  fontWeight: 700,
                                  backgroundColor: surfaceInset,
                                  color: theme.palette.text.secondary,
                                  border: `1px solid ${hairline}`,
                                  transition: 'none',
                                }}
                              >
                                /
                              </Box>
                            )}
                            <Typography sx={{ fontSize: '0.85rem' }} noWrap>
                              {note.title || 'Untitled'}
                            </Typography>
                          </ListItemButton>
                        </ListItem>
                      );
                    })}
                  </>
                )}
                {filteredTags.length > 0 && (
                  <>
                    <ListItem
                      sx={{
                        py: 0.5,
                        px: 1.25,
                        mt: (filteredSystemCommands.length > 0 || filteredNotes.length > 0)
                          ? 0.5
                          : 0.25,
                      }}
                    >
                      <Typography
                        sx={{
                          ...monoSectionLabelSx,
                          fontSize: '0.58rem',
                          display: 'inline-flex',
                          alignItems: 'center',
                          gap: 0.5,
                        }}
                      >
                        <TagIcon sx={{ fontSize: 10 }} /> Tags
                      </Typography>
                    </ListItem>
                    {filteredTags.map((tag, idx) => {
                      const flatIdx = filteredSystemCommands.length + filteredNotes.length + idx;
                      return (
                        <ListItem key={tag} disablePadding sx={{ px: 0.5 }}>
                          <ListItemButton
                            data-mention-item="true"
                            selected={flatIdx === selectedIndex}
                            onMouseDown={(e) => { e.preventDefault(); insertTag(tag); }}
                            onClick={(e) => { e.preventDefault(); insertTag(tag); }}
                            sx={{
                              py: 0.75,
                              px: 1.25,
                              borderRadius: 1.25,
                              '&.Mui-selected': {
                                backgroundColor: violetSoft,
                                '&:hover': { backgroundColor: violetSoft },
                              },
                              '&:hover': { backgroundColor: violetSofter },
                            }}
                          >
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, width: '100%' }}>
                              <Chip
                                label={formatTagForDisplay(tag, true)}
                                size="small"
                                sx={{ ...getTagChipStyles(tag, theme), height: 20, fontSize: '0.7rem' }}
                              />
                              {isGroupedTag(tag) && (
                                <Typography
                                  sx={{ fontSize: '0.72rem', color: theme.palette.text.secondary }}
                                >
                                  {getTagGroup(tag)}
                                </Typography>
                              )}
                            </Box>
                          </ListItemButton>
                        </ListItem>
                      );
                    })}
                  </>
                )}
              </>
            )}
          </List>
        </Paper>
      </Popper>
    </Box>
  );
});

AIChatMentionInput.displayName = 'AIChatMentionInput';
export default React.memo(AIChatMentionInput);

